parameters.jsCode:
// Calculate total deductions by summing deductibleAmount from all items
// and grouping by revenue period

const items = $input.all();
const deductionsByPeriod = {};

// Process each item and group by revenue period
for (const item of items) {
  const period = item.json.revenuePeriod || 'Unknown Period';
  const deductibleAmount = parseFloat(item.json.deductibleAmount) || 0;

  if (!deductionsByPeriod[period]) {
    deductionsByPeriod[period] = {
      period: period,
      totalDeductions: 0,
      itemCount: 0,
      items: []
    };
  }

  deductionsByPeriod[period].totalDeductions += deductibleAmount;
  deductionsByPeriod[period].itemCount += 1;
  deductionsByPeriod[period].items.push(item.json);
}

// Convert to array and calculate grand total
const results = Object.values(deductionsByPeriod);
const grandTotal = results.reduce((sum, period) => sum + period.totalDeductions, 0);

// Return summary with period breakdowns
return [
  {
    json: {
      grandTotalDeductions: grandTotal,
      periodBreakdowns: results,
      totalPeriods: results.length,
      totalItems: items.length,
      calculatedAt: new Date().toISOString()
    }
  }
];

